#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long PC, PR;
        scanf("%lld %lld", &PC, &PR);
        long long dC = (PC + 8) / 9;
        long long dR = (PR + 8) / 9;
        if (dC < dR) {
            printf("0 %lld\n", dC);
        } else {
            printf("1 %lld\n", dR);
        }
    }
    return 0;
}

