code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            st = new StringTokenizer(br.readLine());
            long PC = Long.parseLong(st.nextToken());
            long PR = Long.parseLong(st.nextToken());
            long dC = (PC + 8) / 9;
            long dR = (PR + 8) / 9;
            if (dC < dR) sb.append("0 ").append(dC).append('\n');
            else sb.append("1 ").append(dR).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        PC = int(next(it))
        PR = int(next(it))
        dC = (PC + 8) // 9
        dR = (PR + 8) // 9
        if dC < dR:
            out_lines.append(f"0 {dC}")
        else:
            out_lines.append(f"1 {dR}")
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

